// Create a function wrapEvent(nativeEvent) that returns a SyntheticEvent-like object
// It should have:
// - type: from nativeEvent.type
// - target: from nativeEvent.target
// - nativeEvent: reference to the original
// - defaultPrevented: false initially
// - preventDefault(): sets defaultPrevented to true
// - isPropagationStopped: false initially
// - stopPropagation(): sets isPropagationStopped to true

// your code here

const native = { type: 'click', target: { id: 'btn', tagName: 'BUTTON' } };
const synthetic = wrapEvent(native);

console.log('Type: ' + synthetic.type);
console.log('Target: ' + synthetic.target.tagName);
console.log('Has native: ' + (synthetic.nativeEvent === native));

synthetic.preventDefault();
console.log('Prevented: ' + synthetic.defaultPrevented);

synthetic.stopPropagation();
console.log('Stopped: ' + synthetic.isPropagationStopped);

exercises.solution:
function wrapEvent(nativeEvent) {
  return {
    type: nativeEvent.type,
    target: nativeEvent.target,
    nativeEvent: nativeEvent,
    defaultPrevented: false,
    isPropagationStopped: false,
    preventDefault() {
      this.defaultPrevented = true;
    },
    stopPropagation() {
      this.isPropagationStopped = true;
    }
  };
}

const native = { type: 'click', target: { id: 'btn', tagName: 'BUTTON' } };
const synthetic = wrapEvent(native);

console.log('Type: ' + synthetic.type);
console.log('Target: ' + synthetic.target.tagName);
console.log('Has native: ' + (synthetic.nativeEvent === native));

synthetic.preventDefault();
console.log('Prevented: ' + synthetic.defaultPrevented);

synthetic.stopPropagation();
console.log('Stopped: ' + synthetic.isPropagationStopped);

