exercises.solution:
const rules = [
  { name: 'minLength', test: (v) => v.length >= 8, message: 'At least 8 characters' },
  { name: 'hasUpper', test: (v) => /[A-Z]/.test(v), message: 'Contains uppercase letter' },
  { name: 'hasNumber', test: (v) => /[0-9]/.test(v), message: 'Contains a number' }
];

function validatePassword(password) {
  let allPassed = true;
  rules.forEach(rule => {
    const passed = rule.test(password);
    if (!passed) allPassed = false;
    console.log((passed ? 'PASS' : 'FAIL') + ': ' + rule.message);
  });
  return allPassed;
}

console.log('--- Testing "hello" ---');
const r1 = validatePassword('hello');
console.log('All passed: ' + r1);

console.log('--- Testing "Hello123!" ---');
const r2 = validatePassword('Hello123!');
console.log('All passed: ' + r2);

