exercises.solution:
const shortcuts = [
  { key: 's', ctrl: true, action: 'save' },
  { key: 'z', ctrl: true, action: 'undo' },
  { key: 'z', ctrl: true, shift: true, action: 'redo' },
  { key: 'Escape', ctrl: false, action: 'close' }
];

function handleKeyboard(event) {
  const match = shortcuts.find(s =>
    s.key === event.key &&
    s.ctrl === event.ctrlKey &&
    (s.shift || false) === event.shiftKey
  );

  if (match) {
    console.log('Action: ' + match.action);
  } else {
    console.log('No shortcut');
  }
}

handleKeyboard({ key: 's', ctrlKey: true, shiftKey: false });
handleKeyboard({ key: 'z', ctrlKey: true, shiftKey: false });
handleKeyboard({ key: 'z', ctrlKey: true, shiftKey: true });
handleKeyboard({ key: 'Escape', ctrlKey: false, shiftKey: false });
handleKeyboard({ key: 'a', ctrlKey: false, shiftKey: false });

